DELIMITER $$
--
-- Event
--
CREATE DEFINER=`ppmawaro`@`localhost` EVENT `cleanup_old_data` ON SCHEDULE EVERY 1 MONTH STARTS '2025-11-17 06:42:00' ON COMPLETION NOT PRESERVE ENABLE DO BEGIN
    -- Archive data older than 3 years
    -- Clean up old login attempts
    DELETE FROM login_attempts WHERE attempt_time < DATE_SUB(NOW(), INTERVAL 30 DAY);
END$$

